1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	function basePremiumFor(item: any): number {
13	  return BASE_PREMIUM[item.type] ?? 0;
14	}
15	
16	function calculateQuotePremium(items: any[]): number {
17	  const totalBasePremium = items.reduce(
18	    (sum: number, item: any) => sum + basePremiumFor(item),
19	    0,
20	  );
21	
22	  const firstInsurance = totalBasePremium * FIRST_INSURANCE_RATE;
23	  return Math.ceil(totalBasePremium + firstInsurance + PROCESSING_FEE);
24	}
25	
26	export function processScenario(scenario: any): unknown {
27	  const results = scenario.steps.map((step: any) => ({
28	    premium: calculateQuotePremium(step.items),
29	  }));
30	
31	  return { results };
32	}
